var state = {
  vehicle_access: false,
  parking_loading_bay: false,
  access_restrictions: false,
  time_restrictions: false,
  lift_restrictions: false,
  narrow_corridors: false,
  security_procedures: false
};
function fmt(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function reviewDue() {
  var d = new Date();
  d.setFullYear(d.getFullYear() + 1);
  return d.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function render(model) {
  var site = document.getElementById('hdr_site');
  var rdd = document.getElementById('review_due_date');
  var cbn = document.getElementById('completed_by_name');
  if (site) site.textContent = model.site_address || '';
  if (rdd) rdd.textContent = reviewDue();
  if (cbn) cbn.textContent = model.completed_by || 'Current user';
}
window.toggle = function (key) {
  state[key] = !state[key];
  var tog = document.getElementById('tog_' + key.split('_')[0] === 'vehicle' ? 'vehicle' : key.replace('_restrictions', '').replace('_procedures', '').replace('_loading_bay', 'parking').replace('_corridors', 'corridors'));
  var keyMap = {
    vehicle_access: 'vehicle',
    parking_loading_bay: 'parking',
    access_restrictions: 'access',
    time_restrictions: 'time',
    lift_restrictions: 'lift',
    narrow_corridors: 'corridors',
    security_procedures: 'security'
  };
  var short = keyMap[key];
  var btn = document.getElementById('tog_' + short);
  var lbl = document.getElementById('lbl_' + short);
  var con = document.getElementById('con_' + short);
  if (!btn) return;
  var val = state[key];
  btn.className = 'toggle ' + (val ? 'on' : 'off');
  lbl.textContent = val ? 'Yes' : 'No';
  if (con) con.className = 'conditional' + (val ? ' show' : '');
};
window.skipSurvey = function () {
  appsmith.triggerEvent('onSkipSurvey');
};
window.saveSurvey = function () {
  appsmith.updateModel({
    ss_vehicle_access: state.vehicle_access,
    ss_vehicle_access_notes: document.getElementById('f_vehicle_notes').value,
    ss_parking_loading_bay: state.parking_loading_bay,
    ss_parking_notes: document.getElementById('f_parking_notes').value,
    ss_access_restrictions: state.access_restrictions,
    ss_access_restriction_notes: document.getElementById('f_access_notes').value,
    ss_time_restrictions: state.time_restrictions,
    ss_time_restriction_notes: document.getElementById('f_time_notes').value,
    ss_equipment_floor: document.getElementById('f_equipment_floor').value,
    ss_floor_access_type: document.getElementById('f_floor_access_type').value,
    ss_lift_restrictions: state.lift_restrictions,
    ss_lift_notes: document.getElementById('f_lift_notes').value,
    ss_narrow_corridors: state.narrow_corridors,
    ss_corridor_notes: document.getElementById('f_corridor_notes').value,
    ss_security_procedures: state.security_procedures,
    ss_security_details: document.getElementById('f_security_details').value,
    ss_driver_instructions: document.getElementById('f_driver_instructions').value
  });
  appsmith.triggerEvent('onSaveSurvey');
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

